code = """import json
import re

# Load all articles from file
file_path = locals()['var_functions.query_db:12']
with open(file_path, 'r') as f:
    articles = json.load(f)

# Comprehensive sports pattern
sports_terms = [
    # Direct sports
    r'\b(football|basketball|baseball|soccer|tennis|golf|cricket|rugby|hockey|volleyball|handball|wrestling|boxing|swimming|athletics|track|field)\b',
    # Events
    r'\b(olympic|olympics|world cup|championship|tournament|finals|playoff|playoffs|medal|medalist|gold|silver|bronze)\b',
    # Organizations
    r'\b(nfl|nba|mlb|nhl|fifa|uefa|pga|lpga|ncaa|wimbledon|us open|australian open|french open|roland garros|masters|premier league|la liga|bundesliga|serie a|champions league|europa league|world series|super bowl|stanley cup)\b',
    # Venues
    r'\b(stadium|arena|pitch|court|field|track|circuit|racetrack)\b',
    # General terms
    r'\b(game|match|player|players|team|teams|coach|coaches|season|league|scored|goal|goals|points|victory|defeat|win|won|wins|loss|losses|coach|coaching|referee|umpire|athlete|athletes|spectator|fans)\b',
    # Teams (common names)
    r'\b(yankees|red sox|dodgers|mets|cubs|white sox|angels|astros|athletics|braves|brewers|cardinals|giants|indians|marlins|mariners|nationals|orioles|padres|phillies|pirates|rangers|rays|reds|rockies|royals|tigers|twins)\b',
    r'\b(cowboys|patriots|eagles|steelers|packers|giants|bears|vikings|lions|texans|colts|saints|panthers|falcons|seahawks|cardinals|rams|49ers|broncos|chiefs|raiders|chargers|bengals|browns|jaguars|titans|ravens|bills|dolphins|jets)\b',
    r'\b(lakers|warriors|celtics|cavaliers|bulls|spurs|heat|rockets|thunder|raptors|knicks|nets|sixers|bucks|pistons|pacers|hawks|hornets|grizzlies|pelicans|trail blazers|jazz|nuggets|timberwolves|suns|kings|mavericks|wizards|magic)\b'
]

sports_articles = []
sports_pattern = re.compile('|'.join(sports_terms), re.IGNORECASE)

for article in articles:
    text_to_check = f"{article['title']} {article['description']}".lower()
    
    # Check for sports content
    has_sports = bool(sports_pattern.search(text_to_check)) or 'sport' in text_to_check
    
    # Also check for specific edge cases
    if not has_sports:
        # Check for ESPN
        if 'espn' in text_to_check:
            has_sports = True
        # Check for sports team patterns like "FC" (football clubs)
        elif re.search(r'\b\w+\s+FC\b', article['title']) or re.search(r'\b\w+\s+FC\b', article['description']):
            has_sports = True
        # Check for sports player patterns
        elif re.search(r'\b\w+\s+\d{1,2}[A-Z]?\b.*\b\d{1,3}\b|\b\d{1,3}-\d{1,3}\s+\w+\b', text_to_check):
            # Pattern like "Name 23" or "23-24 score" in context
            if any(word in text_to_check for word in ['wins', 'defeats', 'beats', 'score', 'victory', 'defeat']):
                has_sports = True
    
    if has_sports:
        sports_articles.append({
            'article_id': int(article['article_id']),
            'title': article['title'],
            'description': article['description'],
            'desc_length': len(article['description'])
        })

# Find the sports article with the longest description
if sports_articles:
    longest_article = max(sports_articles, key=lambda x: x['desc_length'])
    result = {
        'total_sports_articles': len(sports_articles),
        'longest_sports_article': longest_article
    }
else:
    result = {
        'total_sports_articles': 0,
        'message': 'No sports articles found in the dataset'
    }

print('__RESULT__:')
print(json.dumps(result, indent=2))"""

